-- Starter band: lesson-specific sentences + refreshed exercises

on conflict (id) do update set
  hanzi = excluded.hanzi,
  pinyin = excluded.pinyin,
  english = excluded.english,
  difficulty = excluded.difficulty,
  grammar_notes = excluded.grammar_notes;

delete from lesson_sentences where lesson_id in ('lesson-sa-1', 'lesson-sa-2', 'lesson-sa-3', 'lesson-sa-4', 'lesson-sa-5', 'lesson-sa-6', 'lesson-sa-7', 'lesson-sa-8', 'lesson-sa-9', 'lesson-sa-10', 'lesson-sb-1', 'lesson-sb-2', 'lesson-sb-3', 'lesson-sb-4', 'lesson-sb-5', 'lesson-sb-6', 'lesson-sb-7', 'lesson-sb-8', 'lesson-sb-9', 'lesson-sb-10');


delete from exercises where lesson_id like 'lesson-sa-%' or lesson_id like 'lesson-sb-%';

