insert into sentences (id, course_id, hanzi, pinyin, english, difficulty, grammar_notes) values
  ('ss-sa-5-a', 'course-mandarin-1', '你好吗？', 'Nǐ hǎo ma?', 'How are you?', 1, '吗 turns a greeting into a yes/no question'),
  ('ss-sa-5-b', 'course-mandarin-1', '你好，老师！', 'Nǐ hǎo, lǎoshī!', 'Hello, teacher!', 1, null),
  ('ss-sa-6-a', 'course-mandarin-1', '再见，老师！', 'Zàijiàn, lǎoshī!', 'Goodbye, teacher!', 1, null),
  ('ss-sa-6-b', 'course-mandarin-1', '你好！再见！', 'Nǐ hǎo! Zàijiàn!', 'Hello! Goodbye!', 1, 'Short hello and goodbye together'),
  ('ss-sa-7-a', 'course-mandarin-1', '谢谢您！', 'Xièxie nín!', 'Thank you! (polite)', 1, null),
  ('ss-sa-7-b', 'course-mandarin-1', '请！谢谢！', 'Qǐng! Xièxie!', 'Please! Thank you!', 1, null),
  ('ss-sa-8-a', 'course-mandarin-1', '你叫什么名字？', 'Nǐ jiào shénme míngzi?', 'What is your name?', 1, '什么 asks what; 名字 means name'),
  ('ss-sa-8-b', 'course-mandarin-1', '我的名字是小明。', 'Wǒ de míngzi shì Xiǎomíng.', 'My name is Xiaoming.', 1, '的 links a possessor to 名字'),
  ('ss-sa-9-a', 'course-mandarin-1', '你是学生吗？', 'Nǐ shì xuéshēng ma?', 'Are you a student?', 1, '吗 at the end makes a yes/no question'),
  ('ss-sa-9-b', 'course-mandarin-1', '我不是学生。', 'Wǒ bù shì xuéshēng.', 'I am not a student.', 1, '不 negates 是'),
  ('ss-sa-10-a', 'course-mandarin-1', '你好！我叫小明。', 'Nǐ hǎo! Wǒ jiào Xiǎomíng.', 'Hello! My name is Xiaoming.', 1, null),
  ('ss-sa-10-b', 'course-mandarin-1', '谢谢！不客气。再见！', 'Xièxie! Bù kèqi. Zàijiàn!', 'Thank you! You''re welcome. Goodbye!', 1, null),
  ('ss-sb-1-a', 'course-mandarin-1', '我是老师。', 'Wǒ shì lǎoshī.', 'I am a teacher.', 1, null),
  ('ss-sb-1-b', 'course-mandarin-1', '你是老师吗？', 'Nǐ shì lǎoshī ma?', 'Are you a teacher?', 1, null),
  ('ss-sb-2-a', 'course-mandarin-1', '我来自中国。', 'Wǒ láizì Zhōngguó.', 'I come from China.', 2, '来自 + country'),
  ('ss-sb-2-b', 'course-mandarin-1', '你从哪里来？', 'Nǐ cóng nǎlǐ lái?', 'Where do you come from?', 2, null),
  ('ss-sb-3-a', 'course-mandarin-1', '你是老师吗？', 'Nǐ shì lǎoshī ma?', 'Are you a teacher?', 1, null),
  ('ss-sb-3-b', 'course-mandarin-1', '我不是老师。', 'Wǒ bù shì lǎoshī.', 'I am not a teacher.', 1, null),
  ('ss-sb-4-a', 'course-mandarin-1', '一个人。', 'Yī gè rén.', 'One person.', 1, '一 + 个 + noun counts one item'),
  ('ss-sb-4-b', 'course-mandarin-1', '两个学生。', 'Liǎng gè xuéshēng.', 'Two students.', 1, '两 is used before measure words'),
  ('ss-sb-4-c', 'course-mandarin-1', '三个老师。', 'Sān gè lǎoshī.', 'Three teachers.', 1, null),
  ('ss-sb-5-a', 'course-mandarin-1', '四个人。', 'Sì gè rén.', 'Four people.', 1, null),
  ('ss-sb-5-b', 'course-mandarin-1', '五个学生。', 'Wǔ gè xuéshēng.', 'Five students.', 1, null),
  ('ss-sb-5-c', 'course-mandarin-1', '六个老师。', 'Liù gè lǎoshī.', 'Six teachers.', 1, null),
  ('ss-sb-6-a', 'course-mandarin-1', '七个学生。', 'Qī gè xuéshēng.', 'Seven students.', 1, null),
  ('ss-sb-6-b', 'course-mandarin-1', '八个老师。', 'Bā gè lǎoshī.', 'Eight teachers.', 1, null),
  ('ss-sb-6-c', 'course-mandarin-1', '十个学生。', 'Shí gè xuéshēng.', 'Ten students.', 1, null),
  ('ss-sb-7-a', 'course-mandarin-1', '一个学生。', 'Yī gè xuéshēng.', 'One student.', 1, '个 is the general measure word'),
  ('ss-sb-7-b', 'course-mandarin-1', '一个好老师。', 'Yī gè hǎo lǎoshī.', 'A good teacher.', 1, null),
  ('ss-sb-7-c', 'course-mandarin-1', '三个人。', 'Sān gè rén.', 'Three people.', 1, null),
  ('ss-sb-8-a', 'course-mandarin-1', '我二十岁。', 'Wǒ èrshí suì.', 'I am twenty years old.', 2, 'number + 岁 gives age'),
  ('ss-sb-8-b', 'course-mandarin-1', '他几岁？', 'Tā jǐ suì?', 'How old is he?', 2, null),
  ('ss-sb-9-a', 'course-mandarin-1', '这是什么？', 'Zhè shì shénme?', 'What is this?', 2, '这 means this'),
  ('ss-sb-9-b', 'course-mandarin-1', '那是谁？', 'Nà shì shéi?', 'Who is that?', 2, '那 means that'),
  ('ss-sb-9-c', 'course-mandarin-1', '这是老师。', 'Zhè shì lǎoshī.', 'This is a teacher.', 2, null),
  ('ss-sb-10-a', 'course-mandarin-1', '你好！我来自中国。', 'Nǐ hǎo! Wǒ láizì Zhōngguó.', 'Hello! I come from China.', 2, null),
  ('ss-sb-10-b', 'course-mandarin-1', '我是学生。这是什么？', 'Wǒ shì xuéshēng. Zhè shì shénme?', 'I am a student. What is this?', 2, null)
